Kaj izpiše naslednji program? 
(vsaj dva pravilna odgovora 1 točka) 
Pascal: 
var x,y : char; 
procedure abc(var x1,y1:char); 
var x : char; 
procedure fun; 
var x : char; 
begin 
x:='T'; 
inc(x); 
inc(x1); 
writeln(x,x1,y1); 
end; 
begin 
x:=y1; 
writeln(x,x1,y1); 
fun; 
writeln(x,x1,y1); 
end; 
begin 
  x:='A'; 
  y:='B'; 
  abc(x,y); 
  writeln(x,y); 
end. 
C: 
#include <stdio.h> 
char x='A',y='B'; 
void abc (char *x1, char *y1) 
{ 
  char x; 
  x=*y1; 
  printf("%c%c%c\n",x,*x1,*y1); 
  { 
    char x=’T’; 
    x++; 
    (*x1)++; 
    printf("%c%c%c\n",x,*x1,*y1); 
  } 
  printf("%c%c%c\n",x,*x1,*y1); 
} 
void main() 
{ 
  abc(&x,&y); 
  printf("%c%c\n",x,y); 
}
